ght"":""0"",""bottom"":""0"",""left"":""10"",""isLinked"":false},""_margin_tablet"":{""unit"":""px"",""top"":""10"",""right"":""0"",""bottom"":""0"",""left"":""1"",""isLinked"":false},""typography_font_size_mobile"":{""unit"":""px"",""size"":18,""sizes"":[]},""_margin_mobile"":{""unit"":""px"",""top"":""-5.0"",""right"":""0"",""bottom"":""0"",""left"":""10"",""isLinked"":false}},""elements"":[],""widgetType"":""heading""},{""id"":""dd69fdc"",""elType"":""widget"",""settings"":{""html"":""<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <style>
        body {
            font-family: Arial, sans-serif;
            text-align: center;
            margin-top: 0px;
        }
        #timer-container {
            background-color: #E8E1FF; /* Light purple */
            color: #2E1A47; /* Darker text */
            font-size: 1.5em;
            font-weight: bold;
            padding: 7px 10px; /* Adjusted padding */
            border-radius: 8px; /* Rounded corners */
            display: inline-block;
            box-shadow: 0px 1px 3px rgba(0, 0, 0, 0.1); /* Softer shadow */
        }
    </style>
</head>
<body>

    <div id="timer-container">
        <span id="timer">02 : 02 : 32 : 47</span>
    </div>

    <script>
        let timeLeft = (2 * 24 * 60 * 60) + (2 * 60 * 60) + (32 * 60) + 47; // 2 days, 2 hours, 32 mins, 47 secs

        function updateTimer() {
            let days = Math.floor(timeLeft / (24 * 60 * 60));
            let hours = Math.floor((timeLeft % (24 * 60 * 60)) / (60 * 60));
            let minutes = Math.floor((timeLeft % (60 * 60)) / 60);
            let seconds = timeLeft % 60;

            document.getElementById("timer").textContent = 
                `${days.toString().padStart(2, '0')} : ${hours.toString().padStart(2, '0')} : ${minutes.toString().padStart(2, '0')} : ${seconds.toString().padStart(2, '0')}`;

            if (timeLeft > 0) {
                timeLeft--;
            } else {
                clearInterval(timerInterval);
            }
        }

        let timerInterval = setInterval(updateTimer, 1000);
        updateTimer();
    </script>

</body>
</html>"",""_margin_mobile"":{""unit"":""px"",""top"":""0"",""right"":""-0"",""bottom"":""8.0"",""left"":""7.0"",""isLinked"":false},""_padding_mobile"":{""unit"":""px"",""top"":""0"",""right"":""0"",""bottom"":""0"",""left"":""0"",""isLinked"":false},""_element_width"":""auto"",""_margin_tablet"":{""unit"":""px"",""top"":""0"",""right"":""0"",""bottom"":""0"",""left"":""0"",""isLinked"":false},""hide_mobile"":""hidden-mobile""},""elements"":[],""widgetType"":""html""},{""id"":""23c5b31"",""elType"":""widget"",""settings"":{""text"":""Claim Deal"",""align_mobile"":""center"",""typography_typography"":""custom"",""typography_font_family"":""Poppins"",""typography_font_size_mobile"":{""unit"":""px"",""size"":18,""sizes"":[]},""background_color"":""#3948DE"",""border_radius_mobile"":{""unit"":""px"",""top"":""6.0"",""right"":""5.0"",""bottom"":""5.0"",""left"":""5.0"",""isLinked"":false},""text_padding_mobile"":{""unit"":""px"",""top"":""15.0"",""right"":""110"",""bottom"":""15"",""left"":""112"",""isLinked"":false},""link"":{""url"":""https://www.fyphost.com/#deal"",""is_external"":"""",""nofollow"":"""",""custom_attributes"":""""},""custom_css"":""<a href="#" onclick="scrollToMidPricing()" Claim Deal</a>

