  background-color: #e6e6ff;
  padding: 20px;
  border-radius: 15px;
  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
  max-width: 900px;
  margin: 30px auto;
  text-align: center;
}

.contact-box {
  display: flex;
  justify-content: space-around;
  flex-wrap: wrap;
}

.contact-item {
  width: 30%;
  min-width: 200px;
  padding: 10px;
  text-decoration: none;
  color: inherit;
}

.contact-item img {
  width: 50px;
  height: 50px;
  margin-bottom: 10px;
}

.contact-item h3 {
  margin-bottom: 5px;
  font-size: 1.2rem;
  color: #333;
}

.contact-item p {
  color: #555;
