					<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <style>
        body {
            font-family: Arial, sans-serif;
            text-align: center;
            margin-top: 0px;
        }
        #timer-container {
            background-color: #E8E1FF; /* Light purple */
            color: #2E1A47; /* Darker text */
            font-size: 1.5em;
            font-weight: bold;
            padding: 7px 10px; /* Adjusted padding */
            border-radius: 8px; /* Rounded corners */
            display: inline-block;
            box-shadow: 0px 1px 3px rgba(0, 0, 0, 0.1); /* Softer shadow */
        }
    </style>
</head>
<body>

    <div id="timer-container">
        <span id="timer">02 : 02 : 32 : 47</span>
    </div>

    <script>
        let timeLeft = (2 * 24 * 60 * 60) + (2 * 60 * 60) + (32 * 60) + 47; // 2 days, 2 hours, 32 mins, 47 secs

        function updateTimer() {
            let days = Math.floor(timeLeft / (24 * 60 * 60));
            let hours = Math.floor((timeLeft % (24 * 60 * 60)) / (60 * 60));
            let minutes = Math.floor((timeLeft % (60 * 60)) / 60);
            let seconds = timeLeft % 60;

            document.getElementById("timer").textContent = 
                `${days.toString().padStart(2, '0')} : ${hours.toString().padStart(2, '0')} : ${minutes.toString().padStart(2, '0')} : ${seconds.toString().padStart(2, '0')}`;

            if (timeLeft > 0) {
                timeLeft--;
            } else {
                clearInterval(timerInterval);
            }
        }

        let timerInterval = setInterval(updateTimer, 1000);
        updateTimer();
    </script>

</body>
</html>				</div>
